import type { AppContext } from "../context"

const WINDOW_MS = 60_000
const MAX_REQUESTS = 60
const buckets: Record<string, { count: number; resetAt: number }> = {}

export function rateLimit(ctx: AppContext, next: () => Response): Response {
  const ip = ctx.headers["x-forwarded-for"] ?? ctx.headers["x-real-ip"] ?? "unknown"
  const now = Date.now()
  const current = buckets[ip]

  if (current == nil || now >= current.resetAt) {
    buckets[ip] = { count: 1, resetAt: now + WINDOW_MS }
    return next()
  }

  if (current.count >= MAX_REQUESTS) {
    return { status: 429, body: { error: "rate_limited" } }
  }

  current.count = current.count + 1
  return next()
}

import type { AppContext } from "../context"
import { authGuard, rateLimit } from "../middleware"

function withMiddleware(ctx: AppContext, middleware, handler) {
  return middleware(ctx, { -> handler(ctx) })
}

export function handleApiRequest(ctx: AppContext): Response {
  return withMiddleware(ctx, rateLimit, { limited_ctx ->
    return withMiddleware(limited_ctx, authGuard, { authed_ctx ->
      return {
        status: 200,
        body: {
          ok: true,
          user: authed_ctx.state.user,
          route: "/api/projects",
        },
      }
    })
  })
}
